async def search_candidates_recruit_manage(
    keywords: str,
    company: Optional[tuple] = None,
    pages: int = 1,
    browser: Optional[BrowserManager] = None,
    min_years: Optional[int] = None,
    max_years: Optional[int] = None,
) -> List[CandidateBasic]:
    """Search for candidates via the recruit_manage path (Path D).

    For standard paid accounts without enterprise/talent_bank access.
    Navigates same-tab: homepage → #recruiter_manage → search_v2 page.
    Uses structured filters (keyword, position, city, years, company preset tags).
    Candidate card layout matches enterprise, so reuses _extract_enterprise_results().

    Args:
        keywords: Search keywords
        company: Preset company tag names to click (e.g. ("TMDJ", "阿里"))
        pages: Number of scroll-pages to extract
        browser: Browser manager instance
        min_years: Minimum work years filter (multi-selects all ranges >= min_years)
        max_years: Maximum work years threshold (excludes ranges with threshold > max_years)

    Returns:
        List of CandidateBasic objects
    """
    validate_keywords(keywords)

    if browser is None:
        browser = get_browser_manager()

    config = get_config()
    rate_limiter = get_rate_limiter()
    db_manager = get_db_manager()

    await ensure_logged_in(browser)

    all_candidates: List[CandidateBasic] = []
    seen_ids: set = set()

    with Progress(
        SpinnerColumn(),
        TextColumn("[progress.description]{task.description}"),
        console=console,
    ) as progress:
        task = progress.add_task("Opening recruit manage...", total=None)

        try:
            await async_check_rate_limit("search")

            page = browser.page

            # Step 1: Navigate to homepage, click 招聘管理 link
            progress.update(task, description="Navigating to recruit manage...")
            await retry_navigation(page, MAIMAI_HOME_URL, wait_until="domcontentloaded")
            await async_random_delay("page_load")

            entry_sel = config.get_selector("recruit_manage.entry_link")
            entry_link = await page.wait_for_selector(entry_sel, timeout=8000)
            if not entry_link:
                raise SelectorNotFoundError(f"Could not find recruit manage entry: {entry_sel}")
            await entry_link.click()
            await async_random_delay("page_load")

            # Wait for search_v2 URL
            try:
                await page.wait_for_url(
                    lambda url: RECRUIT_MANAGE_URL_MARKER in url,
                    timeout=15000,
                )
            except Exception:
                logger.warning(f"search_v2 URL not matched, current: {page.url}")

            await async_random_delay("action")

            # Step 2: Add keyword filter
            progress.update(task, description=f"Adding keyword: {keywords}")

            add_kw_sel = config.get_selector("recruit_manage.add_keyword_button")
            add_kw_btn = await page.wait_for_selector(add_kw_sel, timeout=5000)
            if add_kw_btn:
                await add_kw_btn.click()
                await async_random_delay("action")

            kw_input_sel = config.get_selector("recruit_manage.keyword_input")
            await page.wait_for_selector(kw_input_sel, timeout=5000)
            await human_type(page, kw_input_sel, keywords)
            await async_random_delay("action")

            kw_submit_sel = config.get_selector("recruit_manage.keyword_submit")
            submit_btn = await page.wait_for_selector(kw_submit_sel, timeout=3000)
            if submit_btn:
                await submit_btn.click()
                await async_random_delay("page_load")

            # Step 3: Set year filter if requested (multi-select ranges >= min_years)
            if min_years:
                progress.update(task, description=f"Setting year filter: {min_years}+...")
                try:
                    add_years_sel = config.get_selector("recruit_manage.add_years_button")
                    years_btn = await page.wait_for_selector(add_years_sel, timeout=5000)
                    if years_btn:
                        await years_btn.click()
                        await async_random_delay("action")

                        # Select year ranges >= min_years and <= max_years
                        applicable = [
                            (threshold, label) for threshold, label in _YEAR_RANGES
                            if threshold >= min_years and (max_years is None or threshold <= max_years)
                        ]
                        if not applicable:
                            applicable = [_YEAR_RANGES[-1]]  # fallback to 10年以上

                        for i, (_, label) in enumerate(applicable):
                            if i > 0:
                                # Click the "+" button within the year section specifically
                                try:
                                    await page.wait_for_timeout(1000)
                                    clicked = await page.evaluate('''(title) => {
                                        const h4s = document.querySelectorAll('h4');
                                        for (const h4 of h4s) {
                                            if (h4.textContent.trim() === title) {
                                                const facet = h4.closest('[class*="facet___"]');
                                                const btn = facet && facet.querySelector('[class*="addConditionButton"]');
                                                if (btn) { btn.click(); return true; }
                                            }
                                        }
                                        return false;
                                    }''', '工作年限')
                                    if clicked:
                                        await page.wait_for_timeout(1500)
                                    else:
                                        logger.debug(f"Could not find + button in year section for: {label}")
                                except Exception:
                                    logger.debug(f"Could not click add condition button for year: {label}")

                            opt = await page.wait_for_selector(f"text='{label}'", timeout=5000)
                            if opt:
                                await opt.click()
                                await page.wait_for_timeout(800)  # wait for tag to settle
                                logger.info(f"Selected year filter: {label}")
                except Exception as e:
                    logger.warning(f"Failed to set year filter: {e}")

            # Step 4: Set company filter if specified (preset tags)
            if company:
                progress.update(task, description="Adding company filter...")
                try:
                    add_co_sel = config.get_selector("recruit_manage.add_company_button")
                    add_co_btn = await page.wait_for_selector(add_co_sel, timeout=5000)
                    if add_co_btn:
                        await add_co_btn.click()
                        await async_random_delay("action")

                    for i, co_name in enumerate(company):
                        if i > 0:
                            # Click the "+" button within the company section specifically
                            try:
                                await page.wait_for_timeout(1000)
                                clicked = await page.evaluate('''(title) => {
                                    const h4s = document.querySelectorAll('h4');
                                    for (const h4 of h4s) {
                                        if (h4.textContent.trim() === title) {
                                            const facet = h4.closest('[class*="facet___"]');
                                            const btn = facet && facet.querySelector('[class*="addConditionButton"]');
                                            if (btn) { btn.click(); return true; }
                                        }
                                    }
                                    return false;
                                }''', '就职公司')
                                if clicked:
                                    await page.wait_for_timeout(1500)
                                else:
                                    logger.debug(f"Could not find + button in company section for: {co_name}")
                            except Exception:
                                logger.debug(f"Could not click add condition button for company: {co_name}")

                        opt = await page.wait_for_selector(f"text='{co_name}'", timeout=5000)
                        if opt:
                            await opt.click()
                            await page.wait_for_timeout(800)  # wait for tag to settle
                            logger.info(f"Selected company filter: {co_name}")
                except Exception as e:
                    logger.warning(f"Failed to set company filter: {e}")

            # Wait for results to load
            await page.wait_for_timeout(3000)
            await check_captcha(page, report_to_rate_limiter=True)

            # Step 5: Extract candidates (with pagination via scroll)
            for page_num in range(1, pages + 1):
                progress.update(task, description=f"Extracting page {page_num}/{pages}...")

                # Reuse enterprise extraction — same card layout
                candidates = await _extract_enterprise_results(page)

                # Deduplicate across scroll pages
                candidates = [c for c in candidates if c.maimai_id not in seen_ids]
                for c in candidates:
                    seen_ids.add(c.maimai_id)

                if not candidates:
                    logger.info(f"No recruit_manage results on page {page_num}")
                    break

                # Filter non-R&D roles
                before_filter = len(candidates)
                candidates = [c for c in candidates if not _is_non_rd_title(c.title)]
                filtered = before_filter - len(candidates)
                if filtered > 0:
                    logger.info(f"Filtered out {filtered} non-R&D candidates")

                all_candidates.extend(candidates)
                progress.update(task, description=f"Page {page_num}: Found {len(candidates)} candidates")

                rate_limiter.log_action("search", {
                    "keywords": keywords,
                    "page": page_num,
                    "results": len(candidates),
                    "mode": "recruit_manage",
                })

                try:
                    _save_candidates_to_db(db_manager, candidates, keywords)
                except Exception as e:
                    console.print(f"[yellow]Warning: Failed to save candidates to DB: {e}[/yellow]")

                # Scroll for next page (infinite scroll)
                if page_num < pages:
                    await human_scroll(page, "down", distance=800)
                    await async_random_delay("page_load")
                    await page.wait_for_timeout(2000)

        except Exception as e:
            logger.error(f"Recruit manage search error: {e}")
            await browser.screenshot("recruit_manage_search_error")
            progress.update(task, description=f"Error: {str(e)[:40]}")

    _log_search_history(db_manager, keywords, company, None, pages, len(all_candidates))

    console.print(f"[green]Recruit manage search complete. Found {len(all_candidates)} candidates.[/green]")
    return all_candidates

