async def _exchange_in_recruit_manage_im(
    im_page: Page,
    exchange_phone: bool,
    exchange_wechat: bool,
) -> None:
    """Click exchange buttons on the recruit_manage IM tab.

    Unlike talent_bank which uses an iframe, recruit_manage opens a regular
    /chat page — selectors are simple text matches on the page itself.

    Args:
        im_page: The IM tab page (URL pattern: /chat?fr=ent&target=...)
        exchange_phone: Click "交换手机"
        exchange_wechat: Click "交换微信"
    """
    try:
        await im_page.wait_for_load_state("domcontentloaded", timeout=8000)
        await im_page.wait_for_timeout(2000)

        if exchange_phone:
            try:
                phone_btn = await im_page.wait_for_selector("text='交换手机'", timeout=5000)
                if phone_btn:
                    await phone_btn.click()
                    logger.info("Recruit manage: clicked 交换手机")
                    await im_page.wait_for_timeout(1500)
            except Exception as e:
                logger.debug(f"Recruit manage: exchange phone failed: {e}")

        if exchange_wechat:
            try:
                wechat_btn = await im_page.wait_for_selector("text='交换微信'", timeout=5000)
                if wechat_btn:
                    await wechat_btn.click()
                    await im_page.wait_for_timeout(1500)
                    # WeChat has a confirmation dialog
                    try:
                        confirm_btn = await im_page.wait_for_selector("text='确定'", timeout=3000)
                        if confirm_btn:
                            await confirm_btn.click()
                            logger.info("Recruit manage: clicked 交换微信 + confirmed")
                            await im_page.wait_for_timeout(1000)
                    except Exception:
                        logger.info("Recruit manage: clicked 交换微信 (no confirm dialog)")
            except Exception as e:
                logger.debug(f"Recruit manage: exchange wechat failed: {e}")

    except Exception as e:
        logger.error(f"Recruit manage exchange error: {e}")


async def send_message_recruit_manage_inline(
    page: Page,
    content: str,
    browser: "BrowserManager",
    config=None,
    exchange_phone: bool = False,
    exchange_wechat: bool = False,
    chat_btn_handle=None,
) -> bool:
    """Send a message inline on the recruit_manage page, optionally exchange.

    Flow: click 立即沟通 → fill textarea → click 发送后继续沟通 →
    new IM tab opens → exchange phone/wechat → close IM tab.

    The IM tab is a regular /chat page (no iframe), simpler than talent_bank.

    Args:
        page: Playwright page on the recruit_manage results page
        content: Message content to send
        browser: BrowserManager for tab management
        config: Config instance (loaded if None)
        exchange_phone: Click "交换手机" in IM tab after sending
        exchange_wechat: Click "交换微信" in IM tab after sending
        chat_btn_handle: Pre-located "立即沟通" button handle

    Returns:
        True if message was sent successfully
    """
    if config is None:
        config = get_config()

    try:
        # Click 立即沟通 (use pre-located handle if available)
        if chat_btn_handle:
            await chat_btn_handle.click()
        else:
            chat_sel = config.get_selector("recruit_manage.chat_now_button")
            chat_btn = await page.wait_for_selector(chat_sel, timeout=5000)
            if not chat_btn:
                logger.warning("Recruit manage: 立即沟通 button not found")
                return False
            await human_click(page, chat_sel)
        await async_random_delay("action")

        # Fill message in textarea
        textarea_sel = config.get_selector("recruit_manage.message_textarea")
        try:
            textarea = await page.wait_for_selector(textarea_sel, timeout=3000)
            if textarea:
                # Force-set value via native setter (React controlled component)
                await textarea.evaluate(
                    """(el, text) => {
                    const setter = Object.getOwnPropertyDescriptor(
                        HTMLTextAreaElement.prototype, 'value'
                    ).set;
                    setter.call(el, '');
                    el.dispatchEvent(new Event('input', { bubbles: true }));
                    setter.call(el, text);
                    el.dispatchEvent(new Event('input', { bubbles: true }));
                    el.dispatchEvent(new Event('change', { bubbles: true }));
                }""",
                    content,
                )
                await async_random_delay("action")
        except Exception:
            logger.debug(
                "Recruit manage: no message textarea found, platform default greeting will be used"
            )

        # Click 发送后继续沟通
        send_sel = config.get_selector("recruit_manage.send_continue_button")
        send_btn = await page.wait_for_selector(send_sel, timeout=5000)
        if not send_btn:
            logger.warning("Recruit manage: send button not found")
            return False

        await human_click(page, send_sel)
        await async_random_delay("action")

        # Wait for IM tab to open
        im_open_ms = config.get("timings.im_tab_open_wait_ms", 3000)
        await page.wait_for_timeout(im_open_ms)

        if (exchange_phone or exchange_wechat) and len(browser.context.pages) <= 1:
            logger.debug("Recruit manage: no new tab yet, waiting extra 3s...")
            await page.wait_for_timeout(3000)

        # --- Exchange in IM tab (regular page, no iframe) ---
        if (exchange_phone or exchange_wechat) and len(browser.context.pages) > 1:
            im_page = None
            for p in browser.context.pages:
                url = p.url.lower()
                if ("/chat" in url or "/im" in url) and p != page:
                    im_page = p
                    break

            if im_page:
                await _exchange_in_recruit_manage_im(im_page, exchange_phone, exchange_wechat)
            else:
                logger.warning("Recruit manage: IM tab not found for exchange")

        # Close IM tabs
        await _close_im_tabs(browser, page)

        logger.info("Recruit manage: message sent inline")
        return True

    except Exception as e:
        logger.error(f"Recruit manage inline send failed: {e}")
        return False


def _make_recruit_manage_sender(
    page: Page,
    browser: BrowserManager,
    config,
    rate_limiter,
    db_manager,
    template_name: str,
    exchange_phone: bool,
    exchange_wechat: bool,
) -> Callable[[dict, str], Awaitable[CandidateSendResult]]:
    """Create a sender callback for recruit_manage inline (Path D)."""

    async def _send(c: dict, content: str) -> CandidateSendResult:
        # Scroll to candidate card and locate its "立即沟通" button
        chat_btn_handle = None
        try:
            name_locator = page.get_by_text(c["name"], exact=False).first
            await name_locator.scroll_into_view_if_needed(timeout=5000)
            await async_random_delay("action")

            name_el = await name_locator.element_handle(timeout=3000)
            if name_el:
                chat_btn_handle = await page.evaluate_handle(
                    """(nameEl) => {
                    let el = nameEl.parentElement;
                    while (el && el !== document.body) {
                        const btns = el.querySelectorAll('span, button, a, div');
                        for (const b of btns) {
                            if (b.textContent.trim() === '立即沟通' && b.childElementCount <= 1) {
                                return b;
                            }
                        }
                        el = el.parentElement;
                    }
                    return null;
                }""",
                    name_el,
                )
                if chat_btn_handle:
                    try:
                        tag = await chat_btn_handle.evaluate("el => el ? el.tagName : null")
                        if not tag:
                            chat_btn_handle = None
                    except Exception:
                        chat_btn_handle = None
        except Exception as e:
            logger.warning(f"Could not locate card button for '{c['name']}': {e}")
            chat_btn_handle = None

        success = await send_message_recruit_manage_inline(
            page,
            content,
            browser,
            config,
            exchange_phone=exchange_phone,
            exchange_wechat=exchange_wechat,
            chat_btn_handle=chat_btn_handle,
        )

        if success:
            rate_limiter.log_action(
                "send_message",
                {
                    "maimai_id": c["maimai_id"],
                    "template": template_name,
                    "mode": "recruit_manage",
                },
            )
            _log_message(db_manager, c["maimai_id"], template_name, content, "sent")
            return CandidateSendResult(success=True, status="sent", content=content)
        else:
            logger.warning(f"Recruit manage inline send failed for {c['name']} ({c['maimai_id']})")
            _log_message(db_manager, c["maimai_id"], template_name, content, "failed")
            return CandidateSendResult(
                success=False,
                status="failed",
                reason="inline send returned False",
                content=content,
            )

    return _send


async def send_message_batch_recruit_manage(
    page: Page,
    candidates: List[dict],
    template_name: str,
    common_variables: Dict[str, str],
    browser: "BrowserManager",
    skip_messaged: bool = True,
    skip_confirmation: bool = False,
    exchange_phone: bool = False,
    exchange_wechat: bool = False,
) -> Dict[str, Any]:
    """Batch send messages inline on the recruit_manage page (Path D)."""
    config = get_config()
    send_one = _make_recruit_manage_sender(
        page,
        browser,
        config,
        get_rate_limiter(),
        get_db_manager(),
        template_name,
        exchange_phone,
        exchange_wechat,
    )

    return await _send_message_batch_common(
        candidates=candidates,
        template_name=template_name,
        common_variables=common_variables,
        send_one=send_one,
        batch_config=BatchConfig(
            mode_label="Recruit Manage Inline",
            panel_title="Recruit Manage Pipeline Summary",
            progress_description="Sending messages (recruit manage)...",
        ),
        skip_messaged=skip_messaged,
        skip_confirmation=skip_confirmation,
    )

