def _make_search_center_sender(
    browser: BrowserManager,
    template_name: str,
    interactive: bool,
    discovered_selectors,
) -> Callable[[dict, str], Awaitable[CandidateSendResult]]:
    """Create a sender callback for search-center (Path A) with retry + timeout."""

    max_retries = 2
    per_candidate_timeout = 90

    async def _send(c: dict, content: str) -> CandidateSendResult:
        variables = {
            "name": c["name"],
            "company": c["company"],
            "position": c["title"],
        }
        last_error = None
        for attempt in range(1 + max_retries):
            try:
                success = await asyncio.wait_for(
                    send_message(
                        maimai_id=c["maimai_id"],
                        template_name=template_name,
                        variables=variables,
                        browser=browser,
                        skip_confirmation=True,
                        interactive=interactive,
                        discovered_selectors=discovered_selectors,
                        _skip_rate_check=True,
                        profile_url=c.get("profile_url"),
                    ),
                    timeout=per_candidate_timeout,
                )
                if success:
                    return CandidateSendResult(
                        success=True,
                        status="sent",
                        attempts=attempt + 1,
                        content=content,
                    )
                last_error = "send returned False"

            except asyncio.TimeoutError:
                console.print(
                    f"[yellow]Timeout for {c['name']} ({c['maimai_id']}), skipping.[/yellow]"
                )
                return CandidateSendResult(
                    success=False,
                    status="failed",
                    reason=f"Timed out after {per_candidate_timeout}s",
                    attempts=attempt + 1,
                    content=content,
                )
            except QuotaExhaustedError as e:
                console.print(f"\n[red]联系券已用尽，终止批量发送[/red]")
                return CandidateSendResult(
                    success=False,
                    status="quota_exhausted",
                    reason=str(e),
                    attempts=attempt + 1,
                    content=content,
                    abort_batch=True,
                )
            except PermanentFailureError as e:
                console.print(f"[yellow]{e}. Skipping.[/yellow]")
                return CandidateSendResult(
                    success=False,
                    status="failed",
                    reason=str(e),
                    attempts=attempt + 1,
                    content=content,
                )
            except RateLimitExceededError as e:
                console.print(f"\n[yellow]Rate limit reached: {e}[/yellow]")
                return CandidateSendResult(
                    success=False,
                    status="rate_limited",
                    reason=str(e),
                    attempts=attempt + 1,
                    content=content,
                    abort_batch=True,
                )
            except Exception as e:
                last_error = str(e)

            # Retry with exponential backoff
            if attempt < max_retries:
                from src.utils.delays import get_retry_delay

                delay = get_retry_delay(attempt, base_delay=3.0, max_delay=30.0)
                logger.info(f"Retry {attempt + 1}/{max_retries} for {c['name']} in {delay:.1f}s")
                await asyncio.sleep(delay)

        # All retries exhausted
        actual_attempts = max_retries + 1
        logger.error(
            f"Failed to send message to {c['name']} after {actual_attempts} attempt(s): {last_error}"
        )
        return CandidateSendResult(
            success=False,
            status="failed",
            reason=last_error or "unknown error",
            attempts=actual_attempts,
            content=content,
        )

    return _send


def _make_enterprise_sender(
    page: Page,
    config,
    rate_limiter,
    db_manager,
    template_name: str,
) -> Callable[[dict, str], Awaitable[CandidateSendResult]]:
    """Create a sender callback for enterprise inline (Path B)."""

    async def _send(c: dict, content: str) -> CandidateSendResult:
        # Scroll to candidate card
        try:
            card_locator = page.get_by_text(c["name"], exact=False).first
            await card_locator.scroll_into_view_if_needed(timeout=5000)
            await async_random_delay("action")
        except Exception as e:
