    try:
        # Dismiss pay equity modal if present (blocks all clicks)
        await page.evaluate("""() => {
            const modal = document.querySelector('.mui-business-pc-pay-equity-modal-wrap');
            if (modal) modal.remove();
            const overlay = document.querySelector('#mui-business-pc-pay');
            if (overlay && overlay.children.length > 0) {
