            await human_click(page, chat_sel)
        await async_random_delay("action")

        # Fill message in textarea
        textarea_sel = config.get_selector("recruit_manage.message_textarea")
        try:
            textarea = await page.wait_for_selector(textarea_sel, timeout=3000)
            if textarea:
                # Force-set value via native setter (React controlled component)
                await textarea.evaluate(
                    """(el, text) => {
                    const setter = Object.getOwnPropertyDescriptor(
                        HTMLTextAreaElement.prototype, 'value'
                    ).set;
                    setter.call(el, '');
                    el.dispatchEvent(new Event('input', { bubbles: true }));
                    setter.call(el, text);
                    el.dispatchEvent(new Event('input', { bubbles: true }));
                    el.dispatchEvent(new Event('change', { bubbles: true }));
                }""",
                    content,
                )
                await async_random_delay("action")
        except Exception:
            logger.debug(
                "Recruit manage: no message textarea found, platform default greeting will be used"
            )

        # Click 发送后继续沟通
        send_sel = config.get_selector("recruit_manage.send_continue_button")
        send_btn = await page.wait_for_selector(send_sel, timeout=5000)
        if not send_btn:
