        if (exchange_phone or exchange_wechat) and len(browser.context.pages) <= 1:
            logger.debug("Recruit manage: no new tab yet, waiting extra 3s...")
            await page.wait_for_timeout(3000)

        # --- Exchange in IM tab (regular page, no iframe) ---
        if (exchange_phone or exchange_wechat) and len(browser.context.pages) > 1:
            im_page = None
            for p in browser.context.pages:
